#include <stdio.h>
#include <stdlib.h>
#include <math.h>

int expmod(int a, int b, int n) {
  if(b == 0)
    return 1;
  else {
    long long res = expmod(a, b/2, n);
    res = (res*res) % n;
    if(b%2 == 1)
      res = (res*a) % n;
    return (int) res;
  }
}

int main()
{
    int n;
    unsigned long long int mod, i;
    mod = 1000000007;
    scanf("%d", &n);
    i = 1;

    int A = 0;
    int B = 1;
    while (i <=n){
       int nB = A * 3LL % mod;
        int nA = (A * 2LL + B) % mod;
        B = nB;
        A = nA;
        i++;
    }
    printf("%d\n", B);
    return 0;
}

